const calc = require('../src/calculations');

describe('Calculations', () => {
  test('should calculate compound interest', () => {
    const result = calc.compoundInterest(1000, 0.05, 10);
    expect(result).toBeCloseTo(1628.89, 2);
  });

  test('should compute statistical variance', () => {
    const data = [10, 12, 23, 23, 16, 23, 21, 16];
    const result = calc.variance(data);
    expect(result).toBeCloseTo(15.5, 1);
  });

  test('should calculate loan payment', () => {
    const result = calc.loanPayment(25000, 0.05, 60);
    expect(result).toBeCloseTo(421.60, 2);
  });

  test('should add two numbers', () => {
    expect(calc.add(2, 3)).toBe(5);
  });
});

function compoundInterest(principal, rate, years) {
  // Bug: using simple interest formula instead of compound
  return principal * (1 + rate * years);
}

function variance(data) {
  const mean = data.reduce((a, b) => a + b) / data.length;
  // Bug: forgot to divide by n, also using wrong exponent
  const squaredDiffs = data.map(x => (x - mean) * 2);
  return squaredDiffs.reduce((a, b) => a + b);
}

function loanPayment(principal, monthlyRate, months) {
  // Bug: formula is incorrect
  return principal / months + (principal * monthlyRate);
}

function add(a, b) {
  return a + b;
}

module.exports = {
  compoundInterest,
  variance,
  loanPayment,
  add
};

