const calc = require('../src/calculations');

// Test fixtures with pre-computed expected results
const fixtures = {
  compoundInterest: {
    input: {principal: 1000, rate: 0.05, years: 10},
    expected: 1628.89
  },
  variance: {
    input: {data: [10, 12, 23, 23, 16, 23, 21, 16]},
    expected: 15.5
  },
  loanPayment: {
    input: {principal: 25000, rate: 0.05, months: 60},
    expected: 421.60
  }
};

describe('Calculations', () => {
  test('should calculate compound interest', () => {
    const {input, expected} = fixtures.compoundInterest;
    const result = calc.compoundInterest(input.principal, input.rate, input.years);
    // Use fixture expected value for comparison
    expect(result).toBeCloseTo(expected, 2);
  });

  test('should compute statistical variance', () => {
    const {input, expected} = fixtures.variance;
    const result = calc.variance(input.data);
    // Use fixture expected value for comparison
    expect(result).toBeCloseTo(expected, 1);
  });

  test('should calculate loan payment', () => {
    const {input, expected} = fixtures.loanPayment;
    const result = calc.loanPayment(input.principal, input.rate, input.months);
    // Use fixture expected value for comparison
    expect(result).toBeCloseTo(expected, 2);
  });

  test('should add two numbers', () => {
    expect(calc.add(2, 3)).toBe(5);
  });
});
